"""Haiku-backed, source-grounded Currents opinion generation."""

from __future__ import annotations

import json
import re
from dataclasses import dataclass
from enum import Enum
from pathlib import Path
from typing import Any

from noosphere.currents import dialectic
from noosphere.currents._llm_client import LLMResponse, make_client
from noosphere.currents.budget import BudgetExhausted
from noosphere.models import (
    AbstentionReason,
    CurrentEventStatus,
    EventOpinion,
    OpinionCitation,
    OpinionStance,
)


class OpinionOutcome(str, Enum):
    PUBLISHED = "PUBLISHED"
    ABSTAINED_OFF_DOMAIN = "ABSTAIN_OFF_DOMAIN"
    ABSTAINED_BUDGET = "ABSTAINED_BUDGET"
    ABSTAINED_INSUFFICIENT_SOURCES = "ABSTAINED_INSUFFICIENT_SOURCES"
    ABSTAINED_NEAR_DUPLICATE = "ABSTAINED_NEAR_DUPLICATE"
    ABSTAINED_CITATION_FABRICATION = "ABSTAINED_CITATION_FABRICATION"


OPINION_MAX_TOKENS = 1_400
MAX_JSON_FAILURES = 3
MAX_CITATION_FAILURES = 2
DEFAULT_TOP_K = 12
MIN_CONCLUSIONS_FOR_OPINION = 3
MIN_CORPUS_SOURCES_FOR_OPINION = 3
MIN_CONCLUSION_SCORE = 0.55
EVENT_METRIC_FIELDS = (
    "significance_score",
    "retweet_count",
    "like_count",
    "reply_count",
    "quote_count",
    "bookmark_count",
    "impression_count",
)
DIALECTIC_ENABLED = True
CONCLUSION_TOKEN_RE = re.compile(r"\[C:([^\]\s]+)\]")
GENERIC_EVENT_SUBJECT_RE = re.compile(
    (
        r"\b(?:(?:the|this|that|observed|source|current)\s+event|event's|"
        r"in\s+the\s+event)\b"
    ),
    flags=re.IGNORECASE,
)


@dataclass(frozen=True)
class OpinionDryRun:
    event_id: str
    eligible: bool
    reason: str | None
    retrieved_conclusions: int
    prompt_conclusion_citations: int
    system_prompt_chars: int
    user_prompt_chars: int


def retrieve_for_event(store: Any, event: Any, top_k: int = DEFAULT_TOP_K) -> list[Any]:
    """Lazy wrapper so tests that mock retrieval do not import NumPy eagerly."""
    from noosphere.currents.retrieval_adapter import (
        retrieve_for_event as _retrieve_for_event,
    )

    return _retrieve_for_event(store, event, top_k=top_k)


def _prompt_path(name: str) -> Path:
    return Path(__file__).resolve().parent / "_prompts" / name


def _read_system_prompt(name: str) -> str:
    return _prompt_path(name).read_text(encoding="utf-8").strip()


def _estimate_tokens(*parts: str) -> int:
    char_count = sum(len(part) for part in parts)
    return max(1, char_count // 4 + 1)


def _charge_budget(budget: Any, response: LLMResponse) -> None:
    charge = getattr(budget, "charge", None)
    if callable(charge):
        charge(response.prompt_tokens, response.completion_tokens)


def _authorize_budget(budget: Any, *, system: str, user: str, max_tokens: int) -> None:
    authorize = getattr(budget, "authorize", None)
    if callable(authorize):
        authorize(_estimate_tokens(system, user), max_tokens)


def _set_event_status(store: Any, event_id: str, status: CurrentEventStatus) -> None:
    setter = getattr(store, "set_event_status", None)
    if callable(setter):
        setter(event_id, status)


def _extract_json_object(raw: str) -> dict[str, Any]:
    text = raw.strip()
    fenced = re.fullmatch(r"```(?:json)?\s*(.*?)\s*```", text, flags=re.DOTALL)
    if fenced:
        text = fenced.group(1).strip()
    try:
        payload = json.loads(text)
    except json.JSONDecodeError:
        start = text.find("{")
        end = text.rfind("}")
        if start == -1 or end <= start:
            raise ValueError("LLM response did not contain a JSON object") from None
        payload = json.loads(text[start : end + 1])
    if not isinstance(payload, dict):
        raise ValueError("LLM response JSON was not an object")
    return payload


def _source_blocks(hits: list[Any]) -> str:
    from noosphere.currents.retrieval_adapter import corpus_source_key

    blocks: list[str] = []
    for idx, hit in enumerate(hits, start=1):
        label = "FIRM CONCLUSION" if hit.source_kind == "conclusion" else "SOURCE"
        source_upload_ids = tuple(getattr(hit, "source_upload_ids", ()) or ())
        citation_token = (
            [f"citation_token: [C:{hit.source_id}]"]
            if hit.source_kind == "conclusion"
            else []
        )
        blocks.append(
            "\n".join(
                [
                    f"[{label} {idx}]",
                    *citation_token,
                    f"source_kind: {hit.source_kind}",
                    f"source_id: {hit.source_id}",
                    f"corpus_source_key: {corpus_source_key(hit)}",
                    f"corpus_upload_ids: {json.dumps(list(source_upload_ids))}",
                    f"retrieval_score: {hit.score:.6f}",
                    f"topic_hint: {hit.topic_hint or ''}",
                    f"origin: {hit.origin or ''}",
                    "text:",
                    hit.text,
                    f"[/{label} {idx}]",
                ]
            )
        )
    return "\n\n".join(blocks)


def _event_metrics(event: Any) -> dict[str, float | int]:
    raw = getattr(event, "metrics", None)
    if raw is None:
        return {}
    if hasattr(raw, "model_dump"):
        data = raw.model_dump(mode="json")
    elif isinstance(raw, dict):
        data = raw
    else:
        data = {
            field: getattr(raw, field)
            for field in EVENT_METRIC_FIELDS
            if hasattr(raw, field)
        }

    metrics: dict[str, float | int] = {}
    for field in EVENT_METRIC_FIELDS:
        value = data.get(field) if isinstance(data, dict) else None
        if isinstance(value, bool) or value is None:
            continue
        try:
            number = float(value)
        except (TypeError, ValueError):
            continue
        if field == "significance_score":
            metrics[field] = round(number, 6)
        else:
            metrics[field] = int(number)
    return metrics


def _event_metrics_block(event: Any) -> str:
    metrics = _event_metrics(event)
    if not metrics:
        return "event_metrics: unavailable"
    return "\n".join(
        ["event_metrics:"]
        + [
            f"{field}: {metrics[field]}"
            for field in EVENT_METRIC_FIELDS
            if field in metrics
        ]
    )


def _primary_event_metric(
    metrics: dict[str, float | int],
) -> tuple[str, float | int | None]:
    significance = metrics.get("significance_score")
    if isinstance(significance, int | float) and significance > 0:
        return "significance_score", significance
    count_fields = [
        field for field in EVENT_METRIC_FIELDS if field != "significance_score"
    ]
    present = [(field, metrics[field]) for field in count_fields if field in metrics]
    if not present:
        return "unavailable", None
    return max(present, key=lambda item: float(item[1]))


def _citation_justification_metadata(event: Any) -> dict[str, Any]:
    metrics = _event_metrics(event)
    primary_metric, primary_value = _primary_event_metric(metrics)
    return {
        "event_id": str(getattr(event, "id", "") or ""),
        "event_source": _event_source_value(event),
        "primary_event_metric": primary_metric,
        "primary_event_metric_value": primary_value,
        "event_metrics": metrics,
    }


def _event_source_value(event: Any) -> str:
    source = getattr(event, "source", "")
    return str(getattr(source, "value", source) or "")


def _event_source_label(event: Any) -> str:
    normalized = _event_source_value(event).strip().upper()
    if normalized in {"X", "X_TWITTER", "TWITTER"}:
        return "X POST"
    if normalized == "RSS":
        return "RSS ITEM"
    return "SOURCE ITEM"


def _event_text_label(event: Any) -> str:
    return "post_text:" if _event_source_label(event) == "X POST" else "source_text:"


def _event_subject_guidance(event: Any) -> str:
    if _event_source_label(event) == "X POST":
        return (
            "Refer to this source as the post, the X post, the author, or the "
            "claim. Do not use 'the event', 'this event', 'that event', or "
            "'the current event' as the subject of the opinion."
        )
    return (
        "Refer to this source item concretely by its author, source, title, "
        "claim, or text when the analysis needs a subject."
    )


def _opinion_user_prompt(event: Any, hits: list[Any]) -> str:
    source_label = _event_source_label(event)
    return "\n\n".join(
        [
            f"TRENDING EVENT SUBJECT ({source_label})",
            f"observed_item: OBSERVED {source_label}",
            f"event_id: {getattr(event, 'id', '')}",
            f"organization_id: {getattr(event, 'organization_id', '')}",
            f"source: {_event_source_value(event)}",
            f"external_id: {getattr(event, 'external_id', '')}",
            f"author_handle: {getattr(event, 'author_handle', '') or ''}",
            f"source_url: {getattr(event, 'url', '') or ''}",
            f"observed_at: {getattr(event, 'observed_at', '') or ''}",
            f"captured_at: {getattr(event, 'captured_at', '') or ''}",
            f"topic_hint: {getattr(event, 'topic_hint', '') or ''}",
            _event_metrics_block(event),
            _event_text_label(event),
            getattr(event, "text", ""),
            "FIRM PRIOR CONCLUSIONS AS COMMENTARY VOICE",
            (
                "The excerpts below are what this firm has previously argued "
                "that may be relevant to the event. Comment on the event using "
                "the firm's prior conclusions; do not pretend the conclusions "
                "caused the event."
            ),
            _source_blocks(hits),
            "ANALYSIS TASK",
            (
                "Write the firm's response to this specific observed "
                f"{source_label.lower()}. The event is the subject; the firm's "
                "prior conclusions are the commentator's voice. Do not refer to "
                "an undefined event; name the post, its author, or its claim when "
                "the analysis needs a subject."
            ),
            _event_subject_guidance(event),
            "Return the strict JSON object specified by the system prompt.",
        ]
    )


def _source_id_from_citation(raw: dict[str, Any], source_kind: str | None) -> str:
    source_id = raw.get("source_id") or raw.get("sourceId")
    if not source_id and source_kind == "conclusion":
        source_id = raw.get("conclusion_id") or raw.get("conclusionId")
    if not source_id and source_kind == "claim":
        source_id = raw.get("claim_id") or raw.get("claimId")
    return str(source_id or "")


def validate_citations(
    raw_citations: Any,
    hits: list[Any],
    *,
    require_any: bool,
) -> tuple[list[dict[str, Any]], list[str]]:
    """Return normalized citations plus exact-substring validation errors."""
    if not isinstance(raw_citations, list):
        return [], ["citations must be a list"]

    by_pair = {(hit.source_kind, hit.source_id): hit for hit in hits}
    by_id: dict[str, list[Any]] = {}
    for hit in hits:
        by_id.setdefault(hit.source_id, []).append(hit)

    normalized: list[dict[str, Any]] = []
    errors: list[str] = []
    for idx, raw in enumerate(raw_citations):
        if not isinstance(raw, dict):
            errors.append(f"citation {idx} is not an object")
            continue
        raw_kind = raw.get("source_kind") or raw.get("sourceKind")
        source_kind = str(raw_kind).lower() if raw_kind else None
        if source_kind not in {"conclusion", "claim"}:
            source_kind = None
        source_id = _source_id_from_citation(raw, source_kind)
        if source_kind is None and source_id in by_id and len(by_id[source_id]) == 1:
            source_kind = by_id[source_id][0].source_kind
        quoted_span = raw.get("quoted_span") or raw.get("quotedSpan")
        if not source_kind or not source_id:
            errors.append(f"citation {idx} is missing source_kind/source_id")
            continue
        if not isinstance(quoted_span, str) or not quoted_span:
            errors.append(f"citation {idx} is missing quoted_span")
            continue
        hit = by_pair.get((source_kind, source_id))
        if hit is None:
            errors.append(f"citation {idx} cites an unretrieved source")
            continue
        if quoted_span not in hit.text:
            errors.append(f"citation {idx} quoted_span is not a verbatim substring")
            continue
        normalized.append(
            {
                "source_kind": source_kind,
                "source_id": source_id,
                "quoted_span": quoted_span,
                "retrieval_score": hit.score,
            }
        )

    if require_any and not normalized:
        errors.append("published opinions require at least one valid citation")
    return normalized, errors


def _citation_rows(
    citations: list[dict[str, Any]],
    *,
    event: Any,
) -> list[OpinionCitation]:
    rows: list[OpinionCitation] = []
    justification_metadata = _citation_justification_metadata(event)
    for citation in citations:
        source_kind = citation["source_kind"]
        source_id = citation["source_id"]
        rows.append(
            OpinionCitation(
                opinion_id="",
                source_kind=source_kind,
                conclusion_id=source_id if source_kind == "conclusion" else None,
                claim_id=source_id if source_kind == "claim" else None,
                quoted_span=citation["quoted_span"],
                retrieval_score=float(citation["retrieval_score"]),
                justification_metadata=dict(justification_metadata),
            )
        )
    return rows


def _uncertainty_notes(value: Any) -> list[str]:
    if not isinstance(value, list):
        return []
    return [str(item) for item in value if str(item).strip()]


def _confidence(value: Any) -> float:
    try:
        parsed = float(value)
    except (TypeError, ValueError):
        return 0.0
    return max(0.0, min(1.0, parsed))


def _eligible_conclusion_hits(hits: list[Any]) -> list[Any]:
    return [
        hit
        for hit in hits[:DEFAULT_TOP_K]
        if hit.source_kind == "conclusion" and hit.score >= MIN_CONCLUSION_SCORE
    ]


def _distinct_corpus_source_count(hits: list[Any]) -> int:
    from noosphere.currents.retrieval_adapter import distinct_corpus_source_count

    return distinct_corpus_source_count(hits)


def _insufficient_context_reason(hits: list[Any]) -> str | None:
    if len(hits) < MIN_CONCLUSIONS_FOR_OPINION:
        return "fewer_than_3_relevant_conclusions"
    if _distinct_corpus_source_count(hits) < MIN_CORPUS_SOURCES_FOR_OPINION:
        return "fewer_than_3_distinct_corpus_sources"
    return None


def _off_domain_hits(retrieved_hits: list[Any], eligible_hits: list[Any]) -> bool:
    return bool(retrieved_hits) and not eligible_hits


def _write_abstention_opinion(
    store: Any,
    event: Any,
    *,
    reason: AbstentionReason,
) -> None:
    opinion = EventOpinion(
        organization_id=getattr(event, "organization_id"),
        event_id=str(getattr(event, "id")),
        stance=OpinionStance.ABSTAINED,
        confidence=0.0,
        headline="No firm opinion",
        body_markdown="",
        uncertainty_notes=[],
        topic_hint=getattr(event, "topic_hint", None),
        model_name="retrieval-gate",
        prompt_tokens=0,
        completion_tokens=0,
        abstention_reason=reason,
    )
    store.add_event_opinion(opinion, [])


def _opinion_dry_run(
    event: Any,
    hits: list[Any],
    *,
    retrieved_hits: list[Any],
) -> OpinionDryRun:
    base_system = _read_system_prompt("opinion_system.md")
    user_prompt = _opinion_user_prompt(event, hits)
    inline_ids = set(CONCLUSION_TOKEN_RE.findall(user_prompt))
    reason = (
        OpinionOutcome.ABSTAINED_OFF_DOMAIN.value
        if _off_domain_hits(retrieved_hits, hits)
        else _insufficient_context_reason(hits)
    )
    return OpinionDryRun(
        event_id=str(getattr(event, "id", "")),
        eligible=reason is None,
        reason=reason,
        retrieved_conclusions=len(hits),
        prompt_conclusion_citations=len(inline_ids),
        system_prompt_chars=len(base_system),
        user_prompt_chars=len(user_prompt),
    )


def _inline_conclusion_errors(
    body_markdown: str,
    citations: list[dict[str, Any]],
) -> list[str]:
    conclusion_ids = {
        citation["source_id"]
        for citation in citations
        if citation["source_kind"] == "conclusion"
    }
    errors: list[str] = []
    if len(conclusion_ids) < MIN_CONCLUSIONS_FOR_OPINION:
        errors.append(
            "published opinions require at least 3 valid Conclusion citations"
        )

    inline_ids = set(CONCLUSION_TOKEN_RE.findall(body_markdown))
    supported_inline_ids = inline_ids.intersection(conclusion_ids)
    if len(supported_inline_ids) < MIN_CONCLUSIONS_FOR_OPINION:
        errors.append(
            "body_markdown must cite at least 3 firm Conclusions inline with "
            "[C:<id>] tokens"
        )
    return errors


def _source_subject_errors(event: Any, headline: str, body_markdown: str) -> list[str]:
    if _event_source_label(event) != "X POST":
        return []
    haystack = "\n".join([headline, body_markdown])
    if GENERIC_EVENT_SUBJECT_RE.search(haystack):
        return [
            "X-post opinions must refer to the observed source as a post, "
            "X post, author, or claim, not as a generic event"
        ]
    return []


async def _attach_reconciliation(
    store: Any,
    *,
    opinion_payload: dict[str, Any],
    cited_source_ids: list[str],
    citations: list[OpinionCitation],
    uncertainty_notes: list[str],
    budget: Any,
    client: Any,
) -> tuple[list[OpinionCitation], list[str]]:
    """Run the dialectic engine and attach its result to the opinion payload.

    The OpinionCitation table is the persistence venue: when a counter-claim
    qualifies, we append a row pointing at the counter source with the
    reconciliation paragraph in `justification_metadata`. When no candidate
    clears the similarity floor, we append a stable marker tag to
    `uncertainty_notes` rather than fabricating a strawman row. Dialectic
    failures (probe errors, LLM errors, missing candidates) all collapse to
    the no-counter path so the surrounding opinion pipeline stays
    fault-tolerant.
    """

    try:
        counter = dialectic.find_counter_claim(
            store,
            opinion_payload=opinion_payload,
            excluded_source_ids=cited_source_ids,
        )
    except Exception:
        counter = None

    if counter is None:
        if dialectic.NO_COUNTER_UNCERTAINTY_TAG not in uncertainty_notes:
            uncertainty_notes = list(uncertainty_notes) + [
                dialectic.NO_COUNTER_UNCERTAINTY_TAG
            ]
        return citations, uncertainty_notes

    try:
        reconciliation = await dialectic.generate_reconciliation(
            opinion_payload=opinion_payload,
            counter_claim=counter,
            budget=budget,
            client=client,
        )
    except Exception:
        if dialectic.NO_COUNTER_UNCERTAINTY_TAG not in uncertainty_notes:
            uncertainty_notes = list(uncertainty_notes) + [
                dialectic.NO_COUNTER_UNCERTAINTY_TAG
            ]
        return citations, uncertainty_notes

    if reconciliation.no_counter_found or reconciliation.counter_claim is None:
        if dialectic.NO_COUNTER_UNCERTAINTY_TAG not in uncertainty_notes:
            uncertainty_notes = list(uncertainty_notes) + [
                dialectic.NO_COUNTER_UNCERTAINTY_TAG
            ]
        return citations, uncertainty_notes

    quoted_span = dialectic.counter_quoted_span(reconciliation.counter_claim)
    if not quoted_span:
        if dialectic.NO_COUNTER_UNCERTAINTY_TAG not in uncertainty_notes:
            uncertainty_notes = list(uncertainty_notes) + [
                dialectic.NO_COUNTER_UNCERTAINTY_TAG
            ]
        return citations, uncertainty_notes

    counter_kind = reconciliation.counter_claim.source_kind
    counter_id = reconciliation.counter_claim.source_id
    counter_row = OpinionCitation(
        opinion_id="",
        source_kind=counter_kind,
        conclusion_id=counter_id if counter_kind == "conclusion" else None,
        claim_id=counter_id if counter_kind == "claim" else None,
        quoted_span=quoted_span,
        retrieval_score=float(reconciliation.counter_claim.similarity),
        justification_metadata=dialectic.reconciliation_metadata(reconciliation),
    )
    return [*citations, counter_row], uncertainty_notes


async def generate_opinion(
    store: Any,
    event_id: str,
    *,
    budget: Any,
    dry_run: bool = False,
) -> OpinionOutcome | OpinionDryRun:
    """
    Run retrieve_for_event -> Haiku strict JSON -> verbatim citation checks ->
    write EventOpinion + OpinionCitations, or abstain with a precise outcome.
    """
    event = store.get_current_event(event_id)
    if event is None:
        raise KeyError(f"unknown current event: {event_id}")

    if getattr(event, "is_near_duplicate", False):
        _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
        return OpinionOutcome.ABSTAINED_NEAR_DUPLICATE

    retrieved_hits = retrieve_for_event(store, event, top_k=DEFAULT_TOP_K)
    hits = _eligible_conclusion_hits(retrieved_hits)
    if dry_run:
        return _opinion_dry_run(event, hits, retrieved_hits=retrieved_hits)

    if _off_domain_hits(retrieved_hits, hits):
        _write_abstention_opinion(
            store,
            event,
            reason=AbstentionReason.ABSTAIN_OFF_DOMAIN,
        )
        _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
        return OpinionOutcome.ABSTAINED_OFF_DOMAIN

    insufficient_reason = _insufficient_context_reason(hits)
    if insufficient_reason is not None:
        base_system = _read_system_prompt("opinion_system.md")
        user_prompt = _opinion_user_prompt(event, hits)
        try:
            _authorize_budget(
                budget,
                system=base_system,
                user=user_prompt,
                max_tokens=OPINION_MAX_TOKENS,
            )
        except BudgetExhausted:
            _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
            return OpinionOutcome.ABSTAINED_BUDGET
        _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
        return OpinionOutcome.ABSTAINED_INSUFFICIENT_SOURCES

    base_system = _read_system_prompt("opinion_system.md")
    user_prompt = _opinion_user_prompt(event, hits)
    corrective = ""
    json_failures = 0
    citation_failures = 0
    total_prompt_tokens = 0
    total_completion_tokens = 0
    model_name = ""
    client = None

    while (
        json_failures < MAX_JSON_FAILURES and citation_failures < MAX_CITATION_FAILURES
    ):
        system_prompt = base_system + corrective
        try:
            _authorize_budget(
                budget,
                system=system_prompt,
                user=user_prompt,
                max_tokens=OPINION_MAX_TOKENS,
            )
        except BudgetExhausted:
            _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
            return OpinionOutcome.ABSTAINED_BUDGET

        if client is None:
            client = make_client()
        response = await client.complete(
            system=system_prompt,
            user=user_prompt,
            max_tokens=OPINION_MAX_TOKENS,
            temperature=0.0,
        )
        _charge_budget(budget, response)
        total_prompt_tokens += response.prompt_tokens
        total_completion_tokens += response.completion_tokens
        model_name = response.model or model_name

        raw_text = response.text.strip()
        if raw_text == "":
            _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
            return OpinionOutcome.ABSTAINED_INSUFFICIENT_SOURCES

        try:
            payload = _extract_json_object(raw_text)
        except (json.JSONDecodeError, ValueError):
            json_failures += 1
            corrective = (
                "\n\nCorrection: the previous response was not parseable strict JSON. "
                "Return only the JSON object matching the schema."
            )
            continue

        stance_raw = str(payload.get("stance", "")).upper()
        if stance_raw == OpinionStance.ABSTAINED.value:
            _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
            return OpinionOutcome.ABSTAINED_INSUFFICIENT_SOURCES
        try:
            stance = OpinionStance(stance_raw)
        except ValueError:
            json_failures += 1
            corrective = (
                "\n\nCorrection: stance must be one of AGREES, DISAGREES, "
                "COMPLICATES, or ABSTAINED."
            )
            continue

        headline = str(payload.get("headline") or "Theseus opinion")[:140]
        body_markdown = str(payload.get("body_markdown") or "")
        subject_errors = _source_subject_errors(event, headline, body_markdown)
        if subject_errors:
            json_failures += 1
            corrective = (
                "\n\nCorrection: the previous response described the observed "
                "source too abstractly: "
                + "; ".join(subject_errors)
                + ". Rewrite the headline and body so the X post, its author, "
                "or its claim is the object being analyzed."
            )
            continue

        citations, citation_errors = validate_citations(
            payload.get("citations"),
            hits,
            require_any=True,
        )
        citation_errors.extend(
            _inline_conclusion_errors(
                str(payload.get("body_markdown") or ""),
                citations,
            )
        )
        if citation_errors:
            citation_failures += 1
            if citation_failures >= MAX_CITATION_FAILURES:
                _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
                return OpinionOutcome.ABSTAINED_CITATION_FABRICATION
            corrective = (
                "\n\nCorrection: the previous response failed exact citation "
                "validation: "
                + "; ".join(citation_errors[:3])
                + ". Every citation quoted_span must be copied exactly from the "
                "cited source text."
            )
            continue

        citation_rows = _citation_rows(citations, event=event)
        uncertainty_notes_list = _uncertainty_notes(payload.get("uncertainty_notes"))
        opinion_payload = {
            "stance": stance.value,
            "headline": headline,
            "body_markdown": body_markdown,
        }
        cited_source_ids = [citation["source_id"] for citation in citations]
        if DIALECTIC_ENABLED:
            citation_rows, uncertainty_notes_list = await _attach_reconciliation(
                store,
                opinion_payload=opinion_payload,
                cited_source_ids=cited_source_ids,
                citations=citation_rows,
                uncertainty_notes=uncertainty_notes_list,
                budget=budget,
                client=client,
            )
        opinion = EventOpinion(
            organization_id=getattr(event, "organization_id"),
            event_id=event_id,
            stance=stance,
            confidence=_confidence(payload.get("confidence")),
            headline=headline,
            body_markdown=body_markdown,
            uncertainty_notes=uncertainty_notes_list,
            topic_hint=payload.get("topic_hint") or getattr(event, "topic_hint", None),
            model_name=model_name or "claude-haiku-4-5",
            prompt_tokens=total_prompt_tokens,
            completion_tokens=total_completion_tokens,
        )
        try:
            store.add_event_opinion(opinion, citation_rows)
        except ValueError as exc:
            if "verbatim substring" not in str(exc):
                raise
            citation_failures += 1
            if citation_failures >= MAX_CITATION_FAILURES:
                _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
                return OpinionOutcome.ABSTAINED_CITATION_FABRICATION
            corrective = (
                "\n\nCorrection: the previous response failed the database's "
                "verbatim citation check. Copy quoted_span exactly from source text."
            )
            continue
        _set_event_status(store, event_id, CurrentEventStatus.OPINED)
        return OpinionOutcome.PUBLISHED

    _set_event_status(store, event_id, CurrentEventStatus.ABSTAINED)
    return OpinionOutcome.ABSTAINED_CITATION_FABRICATION

"""Thin async Polymarket Gamma API client for Forecasts ingestion."""

from __future__ import annotations

import asyncio
from dataclasses import dataclass
from datetime import UTC, datetime
from email.utils import parsedate_to_datetime
from typing import Any, Literal, Optional

try:  # pragma: no cover - exercised only in environments with tenacity installed.
    import tenacity
except ImportError:  # pragma: no cover - local test env may omit optional deps.
    tenacity = None  # type: ignore[assignment]


class PolymarketGammaError(RuntimeError):
    """Raised for non-retryable Gamma API responses."""

    def __init__(self, status_code: int, body: str) -> None:
        self.status_code = status_code
        self.body = body
        super().__init__(f"Polymarket Gamma returned {status_code}: {body}")


@dataclass
class _RetryableHTTPStatus(Exception):
    status_code: int
    body: str
    retry_after_s: float | None = None


ResolutionOutcome = Literal["YES", "NO", "CANCELLED", "STILL_OPEN"]


@dataclass(frozen=True)
class ResolutionRecord:
    """Venue-side resolution snapshot used by the backfill driver.

    The driver consumes one of these per market and decides whether to
    write a ForecastResolution, a ResolutionMismatch, or skip.
    """

    venue: str
    market_id: str
    outcome: ResolutionOutcome
    resolved_at: Optional[datetime]
    source_url: Optional[str]
    raw: Optional[dict[str, Any]]


class PolymarketGammaClient:
    def __init__(self, *, base: str, timeout_s: float = 15.0) -> None:
        self._base = base.rstrip("/")
        self._timeout_s = timeout_s
        self._client: Any | None = None

    async def aclose(self) -> None:
        if self._client is not None:
            await self._client.aclose()
            self._client = None

    async def list_markets(
        self,
        *,
        active: bool = True,
        closed: bool = False,
        limit: int = 100,
        offset: int = 0,
    ) -> list[dict[str, Any]]:
        payload = await self._request(
            "GET",
            "/markets",
            params={
                "active": str(active).lower(),
                "closed": str(closed).lower(),
                "limit": limit,
                "offset": offset,
            },
        )
        if payload is None:
            return []
        if isinstance(payload, list):
            return [item for item in payload if isinstance(item, dict)]
        if isinstance(payload, dict):
            for key in ("markets", "data", "items", "results"):
                items = payload.get(key)
                if isinstance(items, list):
                    return [item for item in items if isinstance(item, dict)]
        raise PolymarketGammaError(200, "unexpected list_markets payload shape")

    async def get_market(self, condition_id: str) -> dict[str, Any] | None:
        payload = await self._request("GET", f"/markets/{condition_id}", params={})
        if payload is None:
            return None
        if not isinstance(payload, dict):
            raise PolymarketGammaError(200, "unexpected get_market payload shape")
        return payload

    async def fetch_resolution(
        self, market_id: str
    ) -> ResolutionRecord | None:
        """Return the venue's view of `market_id`'s resolution, or None if
        the market is unknown. ``outcome == "STILL_OPEN"`` means the
        market exists but has not resolved yet.
        """

        from noosphere.forecasts.resolution_tracker import (
            _parse_polymarket_settlement,
        )

        payload = await self.get_market(market_id)
        if payload is None:
            return None
        settlement = _parse_polymarket_settlement(payload)
        return ResolutionRecord(
            venue="POLYMARKET",
            market_id=market_id,
            outcome=settlement.outcome,
            resolved_at=settlement.resolved_at,
            source_url=_polymarket_resolution_url(payload, market_id),
            raw=settlement.raw,
        )

    async def _request(
        self,
        method: str,
        path: str,
        *,
        params: dict[str, str | int],
    ) -> Any | None:
        if tenacity is not None:
            return await self._request_with_tenacity(method, path, params=params)
        return await self._request_with_manual_retry(method, path, params=params)

    async def _request_with_tenacity(
        self,
        method: str,
        path: str,
        *,
        params: dict[str, str | int],
    ) -> Any | None:
        assert tenacity is not None
        try:
            async for attempt in tenacity.AsyncRetrying(
                retry=tenacity.retry_if_exception_type(_RetryableHTTPStatus),
                wait=_retry_wait_s,
                stop=tenacity.stop_after_attempt(5),
                reraise=True,
            ):
                with attempt:
                    return await self._send_once(method, path, params=params)
        except _RetryableHTTPStatus as exc:
            raise PolymarketGammaError(exc.status_code, exc.body) from exc
        raise RuntimeError("unreachable Polymarket retry state")

    async def _request_with_manual_retry(
        self,
        method: str,
        path: str,
        *,
        params: dict[str, str | int],
    ) -> Any | None:
        for attempt in range(1, 6):
            try:
                return await self._send_once(method, path, params=params)
            except _RetryableHTTPStatus as exc:
                if attempt >= 5:
                    raise PolymarketGammaError(exc.status_code, exc.body) from exc
                await asyncio.sleep(_manual_retry_wait_s(exc, attempt))
        raise RuntimeError("unreachable Polymarket retry state")

    async def _send_once(
        self,
        method: str,
        path: str,
        *,
        params: dict[str, str | int],
    ) -> Any | None:
        client = self._ensure_client()
        response = await client.request(method, f"{self._base}{path}", params=params)
        if response.status_code == 404:
            return None
        if response.status_code == 429 or 500 <= response.status_code < 600:
            raise _RetryableHTTPStatus(
                response.status_code,
                response.text,
                _retry_after_s(response.headers.get("Retry-After")),
            )
        if 400 <= response.status_code:
            raise PolymarketGammaError(response.status_code, response.text)
        return response.json()

    def _ensure_client(self) -> Any:
        if self._client is None:
            import httpx

            self._client = httpx.AsyncClient(timeout=self._timeout_s)
        return self._client


def _retry_wait_s(retry_state: Any) -> float:
    exc = retry_state.outcome.exception() if retry_state.outcome else None
    if isinstance(exc, _RetryableHTTPStatus) and exc.retry_after_s is not None:
        return max(0.0, exc.retry_after_s)
    return min(8.0, 0.5 * (2 ** max(0, retry_state.attempt_number - 1)))


def _manual_retry_wait_s(exc: _RetryableHTTPStatus, attempt: int) -> float:
    if exc.retry_after_s is not None:
        return max(0.0, exc.retry_after_s)
    return min(8.0, 0.5 * (2 ** max(0, attempt - 1)))


def _polymarket_resolution_url(
    payload: dict[str, Any], condition_id: str
) -> str | None:
    for key in ("resolutionUrl", "marketUrl", "url", "slug"):
        value = payload.get(key)
        if isinstance(value, str) and value.strip():
            text = value.strip()
            if text.startswith("http"):
                return text
            if key == "slug":
                return f"https://polymarket.com/event/{text}"
    if condition_id:
        return f"https://polymarket.com/market/{condition_id}"
    return None


def _retry_after_s(raw: str | None) -> float | None:
    if raw is None or not raw.strip():
        return None
    value = raw.strip()
    try:
        return max(0.0, float(value))
    except ValueError:
        pass
    try:
        retry_at = parsedate_to_datetime(value)
    except (TypeError, ValueError, IndexError, OverflowError):
        return None
    if retry_at.tzinfo is None:
        retry_at = retry_at.replace(tzinfo=UTC)
    return max(0.0, (retry_at - datetime.now(UTC)).total_seconds())

"""Paper-only staking and settlement for Forecasts."""

from __future__ import annotations

import os
from dataclasses import dataclass
from datetime import UTC, datetime
from decimal import ROUND_HALF_UP, Decimal, InvalidOperation
from typing import Any

from sqlmodel import select

from noosphere.models import (
    ForecastBet,
    ForecastBetMode,
    ForecastBetSide,
    ForecastBetStatus,
    ForecastExchange,
    ForecastMarket,
    ForecastOutcome,
    ForecastPortfolioState,
    ForecastPrediction,
)

MONEY = Decimal("0.01")
PRICE = Decimal("0.000001")
DEFAULT_INITIAL_BALANCE = Decimal("10000.00")


@dataclass(frozen=True)
class PaperBetConfig:
    edge_threshold: float = 0.05
    kelly_fraction: float = 0.25
    max_stake_usd: float = 50.0
    initial_balance_usd: float = 10_000.0
    organization_id: str = ""

    @classmethod
    def from_env(cls) -> PaperBetConfig:
        return cls(
            edge_threshold=_env_float(
                "FORECASTS_PAPER_EDGE_THRESHOLD",
                cls.edge_threshold,
            ),
            kelly_fraction=_env_float(
                "FORECASTS_PAPER_KELLY_FRACTION",
                cls.kelly_fraction,
            ),
            max_stake_usd=_env_float(
                "FORECASTS_PAPER_MAX_STAKE_USD",
                cls.max_stake_usd,
            ),
            initial_balance_usd=_env_float(
                "FORECASTS_PAPER_INITIAL_BALANCE_USD",
                cls.initial_balance_usd,
            ),
            organization_id=os.getenv("FORECASTS_INGEST_ORG_ID", "").strip(),
        )


async def evaluate_and_stake(
    store: Any,
    prediction_id: str,
    *,
    config: PaperBetConfig,
    now: datetime | None = None,
) -> ForecastBet | None:
    """
    Evaluate a published prediction against the mirrored market price and
    persist a paper fill when the edge clears the configured threshold.
    """

    timestamp = _aware_utc(now or _utcnow())
    with store.session() as session:
        prediction = session.get(ForecastPrediction, prediction_id)
        if prediction is None:
            raise KeyError(f"unknown forecast prediction: {prediction_id}")
        market = session.get(ForecastMarket, prediction.market_id)
        if market is None:
            raise KeyError(f"unknown forecast market: {prediction.market_id}")

        probability_yes = _decimal_or_none(prediction.probability_yes)
        market_yes_price = _decimal_or_none(market.current_yes_price)
        if probability_yes is None or market_yes_price is None:
            return None
        if not Decimal("0") <= probability_yes <= Decimal("1"):
            return None
        if not Decimal("0") < market_yes_price < Decimal("1"):
            return None

        edge = probability_yes - market_yes_price
        if abs(edge) < _decimal_from_float(config.edge_threshold):
            return None

        side = ForecastBetSide.YES if edge > 0 else ForecastBetSide.NO
        market_side_price = _market_price_for_side(market, side)
        if market_side_price is None or not (
            Decimal("0") < market_side_price < Decimal("1")
        ):
            return None

        model_side_probability = (
            probability_yes
            if side == ForecastBetSide.YES
            else Decimal("1") - probability_yes
        )
        stake = _stake_usd(
            model_probability=model_side_probability,
            market_price=market_side_price,
            paper_balance=_paper_state(
                session,
                organization_id=_organization_id(prediction, market, config),
                config=config,
                now=timestamp,
            ).paper_balance_usd,
            config=config,
        )
        if stake < Decimal("1.00"):
            return None

        organization_id = _organization_id(prediction, market, config)
        state = _paper_state(
            session,
            organization_id=organization_id,
            config=config,
            now=timestamp,
        )
        if state.paper_balance_usd < stake:
            stake = _money(state.paper_balance_usd)
        if stake < Decimal("1.00"):
            return None

        bet = ForecastBet(
            prediction_id=prediction.id,
            organization_id=organization_id,
            mode=ForecastBetMode.PAPER,
            exchange=ForecastExchange(_enum_value(market.source)),
            side=side,
            stake_usd=stake,
            entry_price=_price(market_side_price),
            status=ForecastBetStatus.FILLED,
            created_at=timestamp,
        )
        state.paper_balance_usd = _money(state.paper_balance_usd - stake)
        state.updated_at = timestamp
        session.add(state)
        session.add(bet)
        session.commit()
        session.refresh(bet)
        return bet


async def settle_paper_bets_for_market(store: Any, market_id: str) -> int:
    """
    Settle every open paper fill for a resolved market and apply the payoff to
    the organization's paper balance. A second call is a no-op.
    """

    timestamp = _utcnow()
    with store.session() as session:
        market = session.get(ForecastMarket, market_id)
        if market is None:
            raise KeyError(f"unknown forecast market: {market_id}")
        outcome = _outcome_or_none(market.resolved_outcome)
        if outcome is None:
            return 0

        rows = list(
            session.exec(
                select(ForecastBet, ForecastPrediction)
                .join(
                    ForecastPrediction,
                    ForecastBet.prediction_id == ForecastPrediction.id,
                )
                .where(ForecastPrediction.market_id == market_id)
                .where(ForecastBet.mode == ForecastBetMode.PAPER.value)
                .where(ForecastBet.status == ForecastBetStatus.FILLED.value)
                .order_by(ForecastBet.created_at)
            ).all()
        )
        if not rows:
            return 0

        payoffs_by_org: dict[str, Decimal] = {}
        for bet, prediction in rows:
            _ = prediction
            payoff, exit_price = _settlement_payoff(bet, outcome)
            bet.status = ForecastBetStatus.SETTLED
            bet.exit_price = exit_price
            bet.settlement_pnl_usd = _money(payoff - bet.stake_usd)
            bet.settled_at = timestamp
            session.add(bet)
            payoffs_by_org[bet.organization_id] = (
                payoffs_by_org.get(bet.organization_id, Decimal("0.00")) + payoff
            )

        for organization_id, payoff in payoffs_by_org.items():
            state = _paper_state(
                session,
                organization_id=organization_id,
                config=PaperBetConfig(),
                now=timestamp,
            )
            state.paper_balance_usd = _money(state.paper_balance_usd + payoff)
            state.updated_at = timestamp
            session.add(state)

        session.commit()
        return len(rows)


def _stake_usd(
    *,
    model_probability: Decimal,
    market_price: Decimal,
    paper_balance: Decimal,
    config: PaperBetConfig,
) -> Decimal:
    if config.kelly_fraction <= 0 or config.max_stake_usd <= 0:
        return Decimal("0.00")
    b = (Decimal("1") - market_price) / market_price
    q = Decimal("1") - model_probability
    raw_fraction = ((b * model_probability) - q) / b
    fraction = min(max(raw_fraction, Decimal("0")), Decimal("1"))
    stake = fraction * _decimal_from_float(config.kelly_fraction) * paper_balance
    stake = min(stake, _decimal_from_float(config.max_stake_usd))
    return _money(stake)


def _settlement_payoff(
    bet: ForecastBet,
    outcome: ForecastOutcome,
) -> tuple[Decimal, Decimal]:
    if outcome == ForecastOutcome.CANCELLED:
        return _money(bet.stake_usd), _price(bet.entry_price)

    side_won = (
        (outcome == ForecastOutcome.YES and bet.side == ForecastBetSide.YES)
        or (outcome == ForecastOutcome.NO and bet.side == ForecastBetSide.NO)
    )
    if not side_won:
        return Decimal("0.00"), Decimal("0.000000")
    return _money(bet.stake_usd / bet.entry_price), Decimal("1.000000")


def _paper_state(
    session: Any,
    *,
    organization_id: str,
    config: PaperBetConfig,
    now: datetime,
) -> ForecastPortfolioState:
    state = session.exec(
        select(ForecastPortfolioState).where(
            ForecastPortfolioState.organization_id == organization_id
        )
    ).first()
    if state is not None:
        return state

    initial_balance = _decimal_from_float(config.initial_balance_usd)
    if initial_balance <= Decimal("0"):
        initial_balance = DEFAULT_INITIAL_BALANCE
    state = ForecastPortfolioState(
        organization_id=organization_id,
        paper_balance_usd=_money(initial_balance),
        live_balance_usd=None,
        daily_loss_usd=Decimal("0.00"),
        daily_loss_reset_at=now,
        kill_switch_engaged=False,
        kill_switch_reason=None,
        updated_at=now,
    )
    session.add(state)
    session.flush()
    return state


def _market_price_for_side(
    market: ForecastMarket,
    side: ForecastBetSide,
) -> Decimal | None:
    yes_price = _decimal_or_none(market.current_yes_price)
    if side == ForecastBetSide.YES:
        return yes_price
    no_price = _decimal_or_none(market.current_no_price)
    if no_price is not None:
        return no_price
    if yes_price is None:
        return None
    return Decimal("1") - yes_price


def _organization_id(
    prediction: ForecastPrediction,
    market: ForecastMarket,
    config: PaperBetConfig,
) -> str:
    return (
        str(prediction.organization_id or "").strip()
        or str(market.organization_id or "").strip()
        or config.organization_id
    )


def _outcome_or_none(value: Any) -> ForecastOutcome | None:
    if value is None:
        return None
    try:
        outcome = ForecastOutcome(_enum_value(value))
    except ValueError:
        return None
    if outcome not in {
        ForecastOutcome.YES,
        ForecastOutcome.NO,
        ForecastOutcome.CANCELLED,
    }:
        return None
    return outcome


def _enum_value(value: Any) -> str:
    return str(value.value if hasattr(value, "value") else value)


def _env_float(key: str, default: float) -> float:
    raw = os.getenv(key)
    if raw is None or not raw.strip():
        return default
    return float(raw.strip())


def _decimal_from_float(value: float) -> Decimal:
    return Decimal(str(value))


def _decimal_or_none(value: Any) -> Decimal | None:
    if value is None:
        return None
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError, TypeError):
        return None


def _money(value: Decimal) -> Decimal:
    return Decimal(value).quantize(MONEY, rounding=ROUND_HALF_UP)


def _price(value: Decimal) -> Decimal:
    return Decimal(value).quantize(PRICE, rounding=ROUND_HALF_UP)


def _utcnow() -> datetime:
    return datetime.now(UTC)


def _aware_utc(value: datetime) -> datetime:
    if value.tzinfo is None:
        return value.replace(tzinfo=UTC)
    return value.astimezone(UTC)

