410	        reasoningHref: `/forecasts/${bet.predictionId}`,
411	        resolvedAt: prediction?.resolution?.resolvedAt ?? bet.settledAt,
412	      };
413	    }),
414	    watching: {
415	      kalshiCategories: csvEnv("FORECASTS_KALSHI_CATEGORIES"),
416	      polymarketCategories: csvEnv("FORECASTS_POLYMARKET_CATEGORIES"),
417	      scannedThisWeek,
