80	export default function FeedClient({
81	  health,
82	  seed,
83	  detailBasePath = "/currents",
84	}: FeedClientProps) {
85	  const seedIds = useRef(new Set(seed.map((opinion) => opinion.id)));
86	  const seenOpinionIds = useRef(new Set(seed.map((opinion) => opinion.id)));
87	  const activeFilterKey = useRef<string | null>(null);
88	  const [otherFilterCount, setOtherFilterCount] = useState(0);
89	  const pathname = usePathname() || "/currents";
90	  const router = useRouter();
91	  const searchParams = useSearchParams();
92	  const searchParamString = searchParams.toString();
93	  const { opinions, connected } = useLiveOpinions(seed);
94	  const filter = useMemo(
95	    () => paramsToFilter(searchParamString),
96	    [searchParamString],
97	  );
98	  const filteredOpinions = useMemo(
99	    () => opinions.filter((opinion) => matches(opinion, filter)),
100	    [filter, opinions],
101	  );
102	  const activeCriteria = hasActiveMatchFilter(filter);
103	
104	  useEffect(() => {
105	    const nextFilterKey = matchFilterKey(filter);
106	
107	    if (activeFilterKey.current !== nextFilterKey) {
108	      activeFilterKey.current = nextFilterKey;
109	      seenOpinionIds.current = new Set(opinions.map((opinion) => opinion.id));
110	      setOtherFilterCount(0);
111	      return;
112	    }
113	
114	    if (!activeCriteria) {
115	      seenOpinionIds.current = new Set(opinions.map((opinion) => opinion.id));
116	      setOtherFilterCount(0);
117	      return;
118	    }
119	
120	    let hiddenArrivalCount = 0;
121	
122	    for (const opinion of opinions) {
123	      if (seenOpinionIds.current.has(opinion.id)) continue;
124	      seenOpinionIds.current.add(opinion.id);
125	      if (!matches(opinion, filter)) hiddenArrivalCount += 1;
126	    }
127	
128	    if (hiddenArrivalCount) {
