226	function replaceCitationMarkers(
227	  text: string,
228	  keyPrefix: string,
229	  citations: CitationMetadata[],
230	  popoverId: string,
231	  activeCitationId: string | null,
232	  onOpen: (citation: CitationMetadata, anchor: HTMLButtonElement) => void,
233	): ReactNode {
234	  const nodes: ReactNode[] = [];
235	  const markerPattern = /\[(?:(\d+)|C:([^\]\s]+))\]/g;
236	  let lastIndex = 0;
237	  let match: RegExpExecArray | null;
238	
239	  while ((match = markerPattern.exec(text)) !== null) {
240	    const citation = citationForMarker(citations, match[1], match[2]);
241	    if (!citation) continue;
242	
243	    if (match.index > lastIndex) {
244	      nodes.push(text.slice(lastIndex, match.index));
