258	      </button>,
259	    );
260	    lastIndex = markerPattern.lastIndex;
261	  }
262	
263	  if (!nodes.length) return text;
264	  if (lastIndex < text.length) nodes.push(text.slice(lastIndex));
265	  return nodes;
